let currentTab='brevet';

function switchTab(tab){
  currentTab=tab;
  document.getElementById('tab-brevet').classList.toggle('active',tab==='brevet');
  document.getElementById('tab-bac').classList.toggle('active',tab==='bac');
  document.getElementById('brevet-info').style.display=tab==='brevet'?'':'none';
  document.getElementById('bac-info').style.display=tab==='bac'?'':'none';
  document.getElementById('pp-title').textContent=tab==='brevet'?'Pays — Brevet':'Pays — Baccalauréat';
  if(currentPays){
    showElist(currentPays);
    if(typeof renderDots==='function') renderDots(currentPays);
  }
}

